// getBracketData returns the paired bracket and open/close status for a rune.
// Returns ok=false if the rune is not a bracketed character.
func getBracketData(r rune) (paired rune, isOpen bool, ok bool) {
	left, right := 0, len(bracketData)-1
	for left <= right {
		mid := (left + right) / 2
		entry := bracketData[mid]
		if r < entry.start {
			right = mid - 1
		} else if r > entry.end {
			left = mid + 1
		} else {
			return entry.paired, entry.isOpen, true
		}
	}
	return 0, false, false
}
